      const storage = createInMemoryStorage();
      const registerResult0 = await interpret(fieldTransformHandler.register({ name: "status-map", requestMapping: "{\"status\":\"if value == \\\"Done\\\" then \\\"completed\\\" else \\\"open\\\"\"}", responseMapping: "{\"completed\":\"status\"}" }), storage);
